boot.artifact:
// inferred-not-tested. ldrs loaders 是 web component:register 你要的那个,再挂它的 <l-*> 标签。
import { ring } from 'https://cdn.jsdelivr.net/npm/ldrs@1.1.9/+esm';
ring.register();                       // defines <l-ring>(customElements.define,已 guard,可重复调用)
const el = document.createElement('l-ring');
el.setAttribute('size', String(data.size ?? 40));
if (data.color != null) el.setAttribute('color', String(data.color));
if (data.speed != null) el.setAttribute('speed', String(data.speed));
if (data.stroke != null) el.setAttribute('stroke', String(data.stroke));
document.getElementById('loader').appendChild(el);
// 换 loader:import { quantum } → quantum.register() → <l-quantum>;多词 kebab,如 dotWave → <l-dot-wave>

boot.widget:
// ldrs 元素在自己的 shadow root 内自渲染、不注入任何全局 CSS —— 直接挂进宿主 shadowRoot。
import { ring } from 'https://cdn.jsdelivr.net/npm/ldrs@1.1.9/+esm';
ring.register();                       // customElements 注册表是全局的(被 customElements.get 守卫)
const el = document.createElement('l-ring');
el.setAttribute('size', String(data.size ?? 40));
if (data.color != null) el.setAttribute('color', String(data.color));
if (data.speed != null) el.setAttribute('speed', String(data.speed));
shadowRoot.appendChild(el);

